(async()=>{const DEBUG=true;const TARGET_VERSION="2026.05.06-STABLE-500-RETRY-ESAS-FOLDER";const URL="https://cdn.jsdelivr.net/gh/AnonymousHer/DMR_PRO_CODE@main/dmr-pro.min.js";const log=(...a)=>{if(DEBUG)console.log("[DMR LOADER]",...a)};try{if(window.__DMR_PRO_RUNNING__){console.warn("[DMR LOADER] Zaten çalışıyor, ikinci kez başlatılmadı.");return;}window.__DMR_PRO_RUNNING__=true;Object.keys(localStorage).filter(k=>k.startsWith("DMR_")).forEach(k=>{log("silindi:",k);localStorage.removeItem(k)});let u=URL+"?v="+Date.now();log("yükleniyor:",u);let r=await fetch(u,{cache:"no-store"});if(!r.ok)throw new Error("HTTP "+r.status);let t=await r.text();window.DMR_LOADER_VERSION=TARGET_VERSION;log("version:",TARGET_VERSION,"boyut:",t.length);(0,eval)(t)}catch(e){window.__DMR_PRO_RUNNING__=false;console.error("[DMR LOADER ERROR]",e);alert("DMR yüklenemedi: "+e.message)}})();